#include <iostream>
using namespace std;

int main() {
    int x = 10;        // outer x
    cout << x << endl;

    {
        int y = 20;    // y only lives here
        int x = 99;    // inner x — shadows outer x
        cout << x << endl;  // prints inner x
        cout << y << endl;
    }
    // y is gone here
    cout << x << endl;  // back to outer x

    return 0;
}

